import json
import traceback
from typing import Any
from pydantic import BaseModel, ValidationError, field_validator
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output
from lfx.schema.message import Message


class PayloadModel(BaseModel):
    dut: list[str]
    requerimento: list[str]


class ValidationOutput(BaseModel):
    success: bool
    data: PayloadModel | None = None
    error: str | None = None
    traceback: str | None = None


class CustomComponent(Component):
    display_name = "JSON Validator"
    description = (
        "Recebe uma string JSON, faz parse com json.loads e valida "
        "o schema com um BaseModel Pydantic. Em sucesso, expõe os campos "
        "individualmente. Em erro, para as branches de dados e emite mensagem de erro."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "shield-check"
    name = "JsonValidatorComponent"

    inputs = [
        MessageTextInput(
            name="json_string",
            display_name="JSON String",
            info="Cole aqui o JSON a ser validado.",
            tool_mode=True,
        ),
    ]

    outputs = [
        Output(display_name="dut",         name="dut",         method="build_dut",         group_outputs=True),
        Output(display_name="requerimento", name="requerimento", method="build_requerimento", group_outputs=True),
        Output(display_name="On Error",    name="on_error",    method="build_on_error",    group_outputs=True),
    ]

    def set_attributes(self, parameters: dict) -> None:
        super().set_attributes(parameters)
        self._cache: ValidationOutput | None = None  # instância, não classe

    def validate_json(self) -> ValidationOutput:
        if getattr(self, "_cache", None) is not None:
            return self._cache

        raw: str = self.json_string

        try:
            parsed: Any = json.loads(raw, strict=False)
        except json.JSONDecodeError as exc:
            self._cache = ValidationOutput(
                success=False,
                error=f"{exc.__class__.__name__}: {exc}",
                traceback=traceback.format_exc(),
            )
            self.status = self._cache
            return self._cache

        try:
            model = PayloadModel(**parsed)
        except (ValidationError, TypeError) as exc:
            # TypeError cobre o caso de `parsed` não ser um dict
            error_msg = str(exc.errors()) if isinstance(exc, ValidationError) else str(exc)
            self._cache = ValidationOutput(
                success=False,
                error=error_msg,
                traceback=traceback.format_exc(),
            )
            self.status = self._cache
            return self._cache

        self._cache = ValidationOutput(success=True, data=model)
        self.status = self._cache
        return self._cache

    def build_dut(self) -> Message:
        result = self.validate_json()
        if not result.success:
            self.stop("dut")
            return Message(text="")
        return Message(text=str(result.data.dut[0]))

    def build_requerimento(self) -> Message:
        result = self.validate_json()
        if not result.success:
            self.stop("requerimento")
            return Message(text="")
        return Message(text=str(result.data.requerimento[0]))

    def build_on_error(self) -> Message:
        result = self.validate_json()
        if result.success:
            self.stop("on_error")
            return Message(text="")
        return Message(text=f"Erro de validação: {result.error}")
